  6240 |     // ctpop(and X, 1) --> and X, 1
  6241 |     unsigned BitWidth = Op0->getType()->getScalarSizeInBits();
  6242 |     if (MaskedValueIsZero(Op0, APInt::getHighBitsSet(BitWidth, BitWidth - 1),
  6243 |                           Q))
  6244 |       return Op0;
  6245 |     break;
  6246 |   }
